import numpy as np

class MemoryStore:
    def __init__(self):
        self.memories = []

    def add(self, content: str, importance: float, timestamp: int):
        self.memories.append({
            'content': content,
            'importance': importance,
            'timestamp': timestamp,
            'access_count': 0
        })

    def access(self, idx: int):
        if idx < 0 or idx >= len(self.memories):
            raise IndexError(f'Memory index {idx} out of range')
        self.memories[idx]['access_count'] += 1

    def score(self, idx: int, current_time: int, decay_rate: float) -> float:
        m = self.memories[idx]
        age = current_time - m['timestamp']
        decay = np.exp(-decay_rate * age)
        return float(m['importance'] * decay + 0.1 * m['access_count'])

    def top_k(self, k: int, current_time: int, decay_rate: float) -> list:
        if not self.memories:
            return []
        scores = [self.score(i, current_time, decay_rate) for i in range(len(self.memories))]
        k = min(k, len(self.memories))
        return list(np.argsort(scores)[::-1][:k])
